$.fn.makeCalendarLink=function(a,b){var c=parseInt(a.date.replace(/-/g,'')+a.startTime.replace(/:/g,''),10);var d=parseInt(a.date.replace(/-/g,'')+a.endTime.replace(/:/g,''),10);var e=(d-c)/100;if(e<0){e=e+2400;var f=new Date(a.date);f.setDate(f.getDate()+1);a.endDate=f.getFullYear()+'-'+((f.getMonth()+1<10)?'0'+(f.getMonth()+1):(f.getMonth()+1))+'-'+f.getDate()}else{a.endDate=a.date}e=e+'';while(e.length<4){e='0'+e}if(typeof b=='undefined')b='google';switch(b){case'yahoo':$(this).attr('href','http://calendar.yahoo.com/?v=60'+'&TITLE='+encodeURIComponent(a.title)+'&ST='+a.date.replace(/-/g,'')+'T'+a.startTime.replace(/:/g,'')+'&DUR='+e+'&in_loc='+encodeURIComponent(a.placename+' - '+a.address)+'&DESC='+encodeURIComponent(a.description)+'&URL='+a.url);break;case'live':$(this).attr('href','http://calendar.live.com/calendar/calendar.aspx?rru=addevent'+'&summary='+encodeURIComponent(a.title)+'&location='+encodeURIComponent(a.placename+' - '+a.address)+'&dtstart='+a.date.replace(/-/g,'')+'T'+a.startTime.replace(/:/g,'')+'&dtend='+a.endDate.replace(/-/g,'')+'T'+a.endTime.replace(/:/g,'')+'&description='+encodeURIComponent(a.description+' - '+a.url));break;case'icalendar':$(this).attr('href','http://cibul.net/ical?'+'dtstart='+a.date.replace(/-/g,'')+'T'+a.startTime.replace(/:/g,'')+'&dtend='+a.endDate.replace(/-/g,'')+'T'+a.endTime.replace(/:/g,'')+'&summary='+encodeURIComponent(a.title)+'&description='+encodeURIComponent(a.description+' - '+a.url)+'&location='+encodeURIComponent(a.placename+' - '+a.address)+'&categories='+encodeURIComponent(a.tags));break;default:$(this).attr('href','http://www.google.com/calendar/event?action=TEMPLATE'+'&text='+encodeURIComponent(a.title)+'&dates='+a.date.replace(/-/g,'')+'T'+a.startTime.replace(/:/g,'')+'/'+a.endDate.replace(/-/g,'')+'T'+a.endTime.replace(/:/g,'')+'&sprop=website:'+a.url+'&details='+encodeURIComponent(a.description+' - '+a.url)+'&location='+encodeURIComponent(a.placename+' - '+a.address))}};var TickedDateTimes=function(e,f){this.init=function(){$(this.options.checkboxDom).each(function(a,b){if($(b).attr('checked'))$(b).attr('checked',false)})};this.onTick=function(c){c.blur();var d=c.index(this.options.checkboxDom);$(this.options.checkboxDom).each(function(a,b){if(a!=d)$(b).attr('checked',false)});e($.extend(this.options.defaultData,{startTime:c.parents(this.options.parentDom).find('.js_start_time').html(),endTime:c.parents(this.options.parentDom).find('.js_end_time').html(),date:c.parents(this.options.parentDom).find('.js_date').html(),placename:c.parents(this.options.parentDom).find('.js_placename').html(),address:c.parents(this.options.parentDom).find('.js_address').html(),locality:c.parents(this.options.parentDom).find('.js_locality').html(),}))};this.options=$.extend({checkboxDom:'input[type="radio"]',parentDom:'li.js_location',defaultData:{}},f);this.init()};